            now = datetime.now()
            data = {capi.get_security_quotes(
                code[80 * pos:80 * (pos + 1)]) for pos in range(int(len(code) / 80) + 1)}

            dd = [i.result() for i in data]
            return (datetime.now() - now).total_seconds()


        #获取全市场行情，原生版
        def original_quotes():
            api = TdxHq_API()
            api.connect(best_ip)
            now = datetime.now()
            data = [api.get_security_quotes(
                code[80 * pos:80 * (pos + 1)]) for pos in range(int(len(code) / 80) + 1)]
            return (datetime.now() - now).total_seconds()

